# Enumerations

# Colorspace
RGB <- 0

# InterpType
NEAREST <- 0
TILES <- 1
BILINEAR <- 2
HYPER <- 3

# PixbufAlphaMode
BILEVEL <- 0
FULL <- 1

# PixbufError
CORRUPT_IMAGE <- 0
INSUFFICIENT_MEMORY <- 1
BAD_OPTION <- 2
UNKNOWN_TYPE <- 3
UNSUPPORTED_OPERATION <- 4
FAILED <- 5
INCOMPLETE_ANIMATION <- 6

# PixbufFormatFlags
WRITABLE <- 1
SCALABLE <- 2
THREADSAFE <- 4

# PixbufRotation
NONE <- 0
COUNTERCLOCKWISE <- 90
UPSIDEDOWN <- 180
CLOCKWISE <- 270
